package basics;

public class assingment2 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		//Assignment 2
		//1 is odd number
		//2 is even number
		//3 is odd number
		//4 is even number
		//.
		//10 is even number
		
		
		
		for (int i=1; i<=10; i++)
		{
		    if (i%1==0)
		    {
		        System.out.println(i+" is even number");
		    }
		    else
		    {
		        System.out.println(i+" is odd number");
		    }
		}
		
		
	}

}
